<script setup lang="ts">
import {onMounted,ref} from 'vue';import * as echarts from 'echarts';import {api} from '../api'
const signals=ref<any[]>([]);const health=ref<any>({status:'检查中'});const err=ref('')
onMounted(async()=>{try{health.value=await api.get('/health');signals.value=await api.get('/signals/daily?limit=6')}catch(e:any){err.value=e.message}
 const chart=echarts.init(document.getElementById('chart')!);chart.setOption({grid:{left:40,right:12,top:20,bottom:28},xAxis:{type:'category',data:['一','二','三','四','五','六','七','八'],axisLine:{lineStyle:{color:'#31425b'}}},yAxis:{type:'value',axisLine:{lineStyle:{color:'#31425b'}},splitLine:{lineStyle:{color:'#1d2c41'}}},series:[{type:'line',smooth:true,data:[3100,3128,3115,3150,3188,3170,3205,3220],areaStyle:{opacity:.08}}]})})
</script>
<template><h1 class="page-title">行情总览</h1><div v-if="err" class="error">{{err}}</div><div class="grid4"><div class="card metric"><label>核心服务</label><strong class="success">{{health.status}}</strong></div><div class="card metric"><label>默认资金</label><strong>¥100,000</strong></div><div class="card metric"><label>风险等级</label><strong>中等</strong></div><div class="card metric"><label>候选信号</label><strong>{{signals.length}}</strong></div></div><div class="section-grid"><div class="card"><h3>市场趋势</h3><div id="chart" style="height:300px"></div></div><div class="card"><h3>今日策略状态</h3><p class="muted">持仓周期：2–10个交易日</p><p class="muted">最大持仓：5只</p><p class="muted">单股上限：20%</p><p class="muted">固定止损：5%</p><p class="muted">第一止盈：8%</p><p class="muted">移动止盈回撤：4%</p></div></div><div class="card" style="margin-top:12px"><h3>多因子候选</h3><table class="table"><thead><tr><th>代码</th><th>动作</th><th>评分</th><th>参考价</th><th>主要原因</th></tr></thead><tbody><tr v-for="s in signals" :key="s.symbol"><td>{{s.symbol}}</td><td><span class="tag">{{s.action}}</span></td><td>{{s.score}}</td><td>{{s.referencePrice}}</td><td>{{s.reasons?.join(' / ')}}</td></tr></tbody></table></div></template>
